Ecco uno schema PostgreSQL completo per eventi append-only multi-tenant:

```sql
-- Schema per eventi append-only multi-tenant
CREATE SCHEMA IF NOT EXISTS event_store;

-- Tabella principale degli eventi
CREATE TABLE event_store.events (
    tenant_id        UUID        NOT NULL,
    stream_id        VARCHAR(200) NOT NULL,
    event_id         UUID        NOT NULL,
    event_type       VARCHAR(100) NOT NULL,
    version          BIGINT      NOT NULL,
    data             JSONB       NOT NULL,
    metadata         JSONB       DEFAULT '{}',
    occurred_at      TIMESTAMPTZ  NOT NULL DEFAULT NOW(),
    created_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_events PRIMARY KEY (tenant_id, stream_id, version),
    CONSTRAINT uq_event_id UNIQUE (tenant_id, event_id)
) PARTITION BY RANGE (created_at);

-- Indici per query e deduplicazione
CREATE INDEX idx_events_tenant_stream_version 
    ON event_store.events (tenant_id, stream_id, version);

CREATE INDEX idx_events_tenant_event_id 
    ON event_store.events (tenant_id, event_id);

CREATE INDEX idx_events_tenant_occurred 
    ON event_store.events (tenant_id, occurred_at DESC);

CREATE INDEX idx_events_tenant_type 
    ON event_store.events (tenant_id, event_type);

-- Indice per keyset pagination
CREATE INDEX idx_events_pagination 
    ON event_store.events (tenant_id, stream_id, occurred_at, version);

-- Funzione per creare partizioni mensili
CREATE OR REPLACE FUNCTION event_store.create_partition(
    partition_date TIMESTAMPTZ,
    partition_name TEXT DEFAULT NULL
) RETURNS TEXT AS $$
DECLARE
    partition_start TEXT;
    partition_end   TEXT;
    partition_table TEXT;
BEGIN
    partition_start := TO_CHAR(partition_date, 'YYYY-MM-01');
    partition_end   := TO_CHAR(partition_date + INTERVAL '1 month', 'YYYY-MM-01');
    partition_table := COALESCE(partition_name, 
        'events_' || TO_CHAR(partition_date, 'YYYY_MM'));

    EXECUTE FORMAT(
        'CREATE TABLE IF NOT EXISTS event_store.%I 
         PARTITION OF event_store.events 
         FOR VALUES FROM (%L) TO (%L)',
        partition_table, partition_start, partition_end
    );

    RETURN partition_table;
END;
$$ LANGUAGE plpgsql;

-- Funzione per inserimento idempotente con deduplicazione
CREATE OR REPLACE FUNCTION event_store.append_event(
    p_tenant_id    UUID,
    p_stream_id    VARCHAR(200),
    p_event_id     UUID,
    p_event_type   VARCHAR(100),
    p_data         JSONB,
    p_metadata     JSONB DEFAULT '{}',
    p_occurred_at  TIMESTAMPTZ DEFAULT NOW()
) RETURNS TABLE (
    version      BIGINT,
    deduplicated BOOLEAN
) AS $$
DECLARE
    v_version BIGINT;
    v_existing UUID;
BEGIN
    -- Verifica deduplicazione
    SELECT event_id INTO v_existing
    FROM event_store.events
    WHERE tenant_id = p_tenant_id 
      AND event_id = p_event_id;

    IF FOUND THEN
        -- Evento già esistente, restituisci versione corrente
        RETURN QUERY 
        SELECT version, TRUE
        FROM event_store.events
        WHERE tenant_id = p_tenant_id 
          AND event_id = p_event_id;
        RETURN;
    END IF;

    -- Calcola nuova versione
    SELECT COALESCE(MAX(version), 0) + 1 INTO v_version
    FROM event_store.events
    WHERE tenant_id = p_tenant_id 
      AND stream_id = p_stream_id;

    -- Inserimento concorrente sicuro
    INSERT INTO event_store.events (
        tenant_id, stream_id, event_id, event_type,
        version, data, metadata, occurred_at
    ) VALUES (
        p_tenant_id, p_stream_id, p_event_id, p_event_type,
        v_version, p_data, p_metadata, p_occurred_at
    );

    RETURN QUERY SELECT v_version, FALSE;
END;
$$ LANGUAGE plpgsql;

-- Funzione per keyset pagination
CREATE OR REPLACE FUNCTION event_store.get_events_paginated(
    p_tenant_id      UUID,
    p_stream_id      VARCHAR(200),
    p_cursor_version BIGINT DEFAULT NULL,
    p_cursor_time    TIMESTAMPTZ DEFAULT NULL,
    p_limit          INTEGER DEFAULT 100,
    p_direction      TEXT DEFAULT 'forward'
) RETURNS TABLE (
    version      BIGINT,
    event_id     UUID,
    event_type   VARCHAR(100),
    data         JSONB,
    metadata     JSONB,
    occurred_at  TIMESTAMPTZ,
    next_cursor  BIGINT
) AS $$
BEGIN
    IF p_direction = 'forward' THEN
        RETURN QUERY
        SELECT 
            e.version,
            e.event_id,
            e.event_type,
            e.data,
            e.metadata,
            e.occurred_at,
            LEAD(e.version) OVER (ORDER BY e.version) AS next_cursor
        FROM event_store.events e
        WHERE e.tenant_id = p_tenant_id
          AND e.stream_id = p_stream_id
          AND (p_cursor_version IS NULL OR e.version > p_cursor_version)
          AND (p_cursor_time IS NULL OR e.occurred_at >= p_cursor_time)
        ORDER BY e.version
        LIMIT p_limit;
    ELSE
        RETURN QUERY
        SELECT 
            e.version,
            e.event_id,
            e.event_type,
            e.data,
            e.metadata,
            e.occurred_at,
            LEAD(e.version) OVER (ORDER BY e.version DESC) AS next_cursor
        FROM event_store.events e
        WHERE e.tenant_id = p_tenant_id
          AND e.stream_id = p_stream_id
          AND (p_cursor_version IS NULL OR e.version < p_cursor_version)
          AND (p_cursor_time IS NULL OR e.occurred_at <= p_cursor_time)
        ORDER BY e.version DESC
        LIMIT p_limit;
    END IF;
END;
$$ LANGUAGE plpgsql;

-- Funzione per strategia di retention partizionata
CREATE OR REPLACE FUNCTION event_store.apply_retention_policy(
    p_tenant_id      UUID DEFAULT NULL,
    p_retention_days INTEGER DEFAULT 90,
    p_batch_size     INTEGER DEFAULT 1000
) RETURNS TABLE (
    partition_name  TEXT,
    events_deleted  BIGINT
) AS $$
DECLARE
    v_partition RECORD;
    v_cutoff_date TIMESTAMPTZ;
    v_deleted     BIGINT;
BEGIN
    v_cutoff_date := NOW() - INTERVAL '1 day' * p_retention_days;

    FOR v_partition IN 
        SELECT 
            pg_class.relname AS partition_name,
            pg_partition_rule.partition_boundary
        FROM pg_class
        JOIN pg_partition_rule ON pg_class.oid = pg_partition_rule.partition_rule_class
        WHERE pg_class.relname LIKE 'events_%'
          AND pg_partition_rule.partition_boundary IS NOT NULL
    LOOP
        -- Verifica se la partizione contiene dati oltre retention
        IF v_partition.partition_boundary::TIMESTAMPTZ < v_cutoff_date THEN
            -- Elimina dati per tenant specifico o tutti
            IF p_tenant_id IS NOT NULL THEN
                DELETE FROM event_store.events
                WHERE tenant_id = p_tenant_id
                  AND created_at < v_cutoff_date
                  AND created_at >= v_partition.partition_boundary;
            ELSE
                DELETE FROM event_store.events
                WHERE created_at < v_cutoff_date
                  AND created_at >= v_partition.partition_boundary;
            END IF;

            GET DIAGNOSTICS v_deleted = ROW_COUNT;

            -- Opzione: droppa partizione se completamente vuota
            IF v_deleted > 0 THEN
                RETURN QUERY SELECT 
                    v_partition.partition_name,
                    v_deleted;
            END IF;
        END IF;
    END LOOP;
END;
$$ LANGUAGE plpgsql;

-- Funzione per creare partizioni future automaticamente
CREATE OR REPLACE FUNCTION event_store.create_future_partitions(
    p_months_ahead INTEGER DEFAULT 3
) RETURNS SETOF TEXT AS $$
DECLARE
    v_current_date DATE;
    v_partition_name TEXT;
BEGIN
    v_current_date := DATE_TRUNC('month', NOW());

    FOR i IN 0..p_months_ahead LOOP
        v_partition_name := 'events_' || TO_CHAR(v_current_date + i * INTERVAL '1 month', 'YYYY_MM');

        PERFORM event_store.create_partition(
            v_current_date + i * INTERVAL '1 month',
            v_partition_name
        );

        RETURN NEXT v_partition_name;
    END LOOP;
END;
$$ LANGUAGE plpgsql;

-- Job scheduler per manutenzione partizioni (opzionale)
CREATE OR REPLACE FUNCTION event_store.maintenance_job()
RETURNS VOID AS $$
BEGIN
    -- Crea partizioni future
    PERFORM event_store.create_future_partitions(3);

    -- Applica retention policy (90 giorni)
    PERFORM event_store.apply_retention_policy(NULL, 90);
END;
$$ LANGUAGE plpgsql;

-- Esempio di utilizzo
COMMENT ON TABLE event_store.events IS 'Event store append-only multi-tenant con partizionamento mensile';
COMMENT ON COLUMN event_store.events.tenant_id IS 'Identificatore tenant per multi-tenancy';
COMMENT ON COLUMN event_store.events.stream_id IS 'Identificatore dello stream di eventi';
COMMENT ON COLUMN event_store.events.event_id IS 'ID univoco evento per deduplicazione';
COMMENT ON COLUMN event_store.events.version IS 'Versione incrementale nello stream';
```

**Caratteristiche principali:**

1. **Multi-tenant**: `tenant_id` come chiave primaria composita
2. **Append-only**: Versioni incrementali, nessuna modifica/cancellazione
3. **Deduplicazione**: `event_id` univoco per tenant con controllo idempotente
4. **Keyset pagination**: Basata su `(tenant_id, stream_id, occurred_at, version)`
5. **Partizionamento mensile**: Retention gestita a livello di partizione
6. **Indici ottimizzati**: Per query comuni e paginazione

**Vantaggi:**
- Isolamento completo dei tenant
- Performance elevata per scritture append-only
- Deduplicazione efficiente senza lock
- Paginazione stabile anche con inserimenti concorrenti
- Gestione semplificata della retention con drop di partizioni
